Implementasi Binary Search Tree (BST) standar dalam Python. Kode ini mencakup struktur node, inserasi, dan deletion dengan handling kasus lengkap (node tanpa anak, satu anak, dua anak).

```python
class TreeNode:
    def __init__(self, key):
        self.key = key
        self.left = None
        self.right = None

class BinarySearchTree:
    def __init__(self):
        self.root = None

    def insert(self, key):
        self.root = self._insert_recursive(self.root, key)

    def _insert_recursive(self, node, key):
        if node is None:
            return TreeNode(key)

        if key < node.key:
            node.left = self._insert_recursive(node.left, key)
        elif key > node.key:
            node.right = self._insert_recursive(node.right, key)
        # Duplicate keys are ignored for strict BST

        return node

    def delete(self, key):
        self.root = self._delete_recursive(self.root, key)

    def _delete_recursive(self, node, key):
        if node is None:
            return node

        if key < node.key:
            node.left = self._delete_recursive(node.left, key)
        elif key > node.key:
            node.right = self._delete_recursive(node.right, key)
        else:
            # Node found
            if node.left is None:
                return node.right
            elif node.right is None:
                return node.left

            # Node with two children: Get inorder successor (smallest in right subtree)
            temp = self._min_value_node(node.right)
            node.key = temp.key
            node.right = self._delete_recursive(node.right, temp.key)

        return node

    def _min_value_node(self, node):
        current = node
        while current.left is not None:
            current = current.left
        return current

    def search(self, key):
        return self._search_recursive(self.root, key)

    def _search_recursive(self, node, key):
        if node is None or node.key == key:
            return node

        if key < node.key:
            return self._search_recursive(node.left, key)
        return self._search_recursive(node.right, key)

    def inorder(self):
        return self._inorder_recursive(self.root)

    def _inorder_recursive(self, node):
        res = []
        if node:
            res = self._inorder_recursive(node.left)
            res.append(node.key)
            res = res + self._inorder_recursive(node.right)
        return res

# Usage Example
if __name__ == "__main__":
    bst = BinarySearchTree()
    keys = [50, 30, 20, 40, 70, 60, 80]

    for k in keys:
        bst.insert(k)

    print(f"Inorder before delete: {bst.inorder()}")

    bst.delete(20)
    print(f"Inorder after delete 20: {bst.inorder()}")

    bst.delete(30)
    print(f"Inorder after delete 30: {bst.inorder()}")

    bst.delete(50)
    print(f"Inorder after delete 50: {bst.inorder()}")
```

### Catatan Teknis & Keamanan

1.  **Kompleksitas Waktu:**
    *   Average Case: O(log n) untuk insert, delete, search.
    *   Worst Case: O(n) jika tree menjadi unbalanced (degenerate).
2.  **Risiko Keamanan (DoS):**
    *   BST standar rentan terhadap **Algorithmic Complexity Attack**. Attacker dapat mengirim input yang sudah terurut (ascending/descending) untuk memaksa tree menjadi linked list.
    *   Ini akan mengubah kompleksitas menjadi O(n), menyebabkan latency tinggi dan potensi Denial of Service pada sistem yang bergantung pada struktur data ini untuk operasi kritis.
3.  **Rekomendasi Production:**
    *   Untuk lingkungan production di PT Sherif Network, jangan gunakan BST standar. Gunakan **AVL Tree** atau **Red-Black Tree** untuk menjamin balance O(log n).
    *   Alternatif lain: Gunakan struktur data built-in yang optimized seperti `dict` (hash map) di Python jika urutan tidak prioritas utama, karena average case O(1).
